const statsRaw = $('Fetch Geo Stats (7 days)').first().json;
const minBidsRaw = $('Fetch Min Bids').first().json;

const stats = statsRaw?.data?.result?.data || statsRaw?.data || (Array.isArray(statsRaw) ? statsRaw : []);
const minBids = minBidsRaw?.data?.result?.data || minBidsRaw?.data || (Array.isArray(minBidsRaw) ? minBidsRaw : []);

if (!Array.isArray(stats)) {
  return [{ json: { error: 'No geo stats data' } }];
}

// Build min bids map
const minBidMap = {};
if (Array.isArray(minBids)) {
  minBids.forEach(mb => {
    minBidMap[mb.country_code] = {
      min: mb.min_bid || 0.001,
      recommended: mb.recommended_bid || 0.005
    };
  });
}

const maxCeiling = Number(0.10);

// Group stats by ad_id, then by country
const adGeoStats = {};
stats.forEach(d => {
  const adId = d.ad_id;
  const country = d.country_code;
  if (!adId || !country) return;

  if (!adGeoStats[adId]) adGeoStats[adId] = {};
  if (!adGeoStats[adId][country]) {
    adGeoStats[adId][country] = { spend: 0, revenue: 0, clicks: 0, shows: 0 };
  }

  adGeoStats[adId][country].spend += d.money || 0;
  adGeoStats[adId][country].revenue += d.postbacks_confirmed_money || 0;
  adGeoStats[adId][country].clicks += d.clicks_count || 0;
  adGeoStats[adId][country].shows += d.shows_count || 0;
});

// Minimum thresholds: don't optimize without enough data
const MIN_CLICKS_FOR_DECISION = 20;
const MIN_SPEND_FOR_DECISION = 5;

const results = [];

for (const adId of Object.keys(adGeoStats)) {
  const geoBids = {};
  const details = [];
  let totalAdClicks = 0;
  let totalAdSpend = 0;

  for (const country of Object.keys(adGeoStats[adId])) {
    const g = adGeoStats[adId][country];
    totalAdClicks += g.clicks;
    totalAdSpend += g.spend;
  }

  // Skip ads without enough data - don't interfere with Smart Bidder warmup
  if (totalAdClicks < MIN_CLICKS_FOR_DECISION || totalAdSpend < MIN_SPEND_FOR_DECISION) {
    continue;
  }

  for (const country of Object.keys(adGeoStats[adId])) {
    const g = adGeoStats[adId][country];
    const roi = g.spend > 0 ? ((g.revenue - g.spend) / g.spend * 100) : 0;
    const ctr = g.shows > 0 ? (g.clicks / g.shows * 100) : 0;
    const minBid = minBidMap[country]?.min || 0.001;
    const recBid = minBidMap[country]?.recommended || 0.005;

    // Skip geos with too few clicks for this ad - not enough signal
    let optimalBid = null;  // null = don't change
    if (g.clicks < 5) {
      // Not enough data for this geo, skip
      details.push({
        country, roi: 0, clicks: g.clicks,
        spend: Math.round(g.spend * 100) / 100, bid: 0, skipped: true
      });
      continue;
    }

    // Calculate optimal bid based on ROI
    if (roi > 50 && g.clicks > 10) {
      optimalBid = recBid * 1.5; // Scale profitable geos
    } else if (roi > 0 && g.clicks > 5) {
      optimalBid = recBid * 1.1;
    } else if (roi < -30 && g.clicks > 10) {
      optimalBid = minBid; // Minimize losing geos
    } else if (roi < -50 && g.spend > 10) {
      optimalBid = 0; // Effectively disable this geo
    } else {
      // Neutral ROI or not enough data - don't change
      details.push({
        country, roi: Math.round(roi * 100) / 100,
        clicks: g.clicks, spend: Math.round(g.spend * 100) / 100, bid: 0, skipped: true
      });
      continue;
    }

    // Enforce bounds
    if (optimalBid > maxCeiling) optimalBid = maxCeiling;
    if (optimalBid > 0 && optimalBid < minBid) optimalBid = minBid;

    if (optimalBid > 0) {
      geoBids[country] = Math.round(optimalBid * 10000) / 10000;
    }

    details.push({
      country, roi: Math.round(roi * 100) / 100,
      clicks: g.clicks, spend: Math.round(g.spend * 100) / 100,
      bid: geoBids[country] || 0
    });
  }

  // Only emit if we have actual geo bid changes
  const activeBids = details.filter(d => !d.skipped && d.bid > 0);
  if (activeBids.length === 0) continue;

  // API only supports one_bid_for_all_geo, so calculate weighted average
  const totalClicks = activeBids.reduce((s, d) => s + d.clicks, 0);
  let weightedBid = 0;
  if (totalClicks > 0) {
    activeBids.forEach(d => {
      weightedBid += d.bid * (d.clicks / totalClicks);
    });
  } else {
    weightedBid = activeBids.reduce((s, d) => s + d.bid, 0) / activeBids.length;
  }

  if (weightedBid > 0) {
    results.push({
      json: {
        ad_id: adId,
        one_bid_for_all_geo: Math.round(weightedBid * 10000) / 10000,
        details: details
      }
    });
  }
}

if (results.length === 0) {
  return [{ json: { action: 'NONE', reason: 'No geo bid changes needed' } }];
}

return results;
